import React, { useState } from 'react';

const TabsShowcase = () => {
  const [activeTab, setActiveTab] = useState<'info' | 'settings' | 'security'>('info');

  return (
    <div className="space-y-6 p-4 dark:bg-slate-900 rounded-xl">
